-- Commercial email intelligence extensions.alter table public.email_messages  add column if not exists commercial_priority integer not null default 0,  add column if not exists commercial_bucket text not null default 'personal',  add column if not exists intent text,  add column if not exists urgency text not null default 'normal',  add column if not exists needs_response boolean not null default false,  add column if not exists response_due_at timestamptz,  add column if not exists responded_at timestamptz,  add column if not exists portal_source text,  add column if not exists captured_lead_id bigint references public.idealista_leads(id) on delete set null;alter table public.email_messages  drop constraint if exists email_messages_bucket_check,  add constraint email_messages_bucket_check check (commercial_bucket in ('active_client','hot_pedido','property_owner','related','personal'));alter table public.email_messages  drop constraint if exists email_messages_urgency_check,  add constraint email_messages_urgency_check check (urgency in ('normal','important','urgent'));create table if not exists public.email_alerts (  id bigserial primary key,  empresa_id bigint references public.empresas(id) on delete cascade,  user_id bigint not null references public.usuarios(id) on delete cascade,  email_message_id bigint not null references public.email_messages(id) on delete cascade,  alert_type text not null,  title text not null,  description text,  severity text not null default 'medium',  due_at timestamptz,  status text not null default 'open',  created_at timestamptz not null default now(),  resolved_at timestamptz,  constraint email_alerts_type_check check (alert_type in ('needs_response','client_no_reply','property_owner','hot_opportunity')),  constraint email_alerts_severity_check check (severity in ('low','medium','high')),  constraint email_alerts_status_check check (status in ('open','resolved','dismissed')),  constraint email_alerts_unique unique (email_message_id, alert_type));create table if not exists public.email_attachments (  id bigserial primary key,  empresa_id bigint references public.empresas(id) on delete cascade,  user_id bigint not null references public.usuarios(id) on delete cascade,  email_message_id bigint not null references public.email_messages(id) on delete cascade,  filename text not null,  mime_type text,  size_bytes bigint,  provider_attachment_id text,  storage_path text,  document_type text not null default 'otro',  linked_entity_type text,  linked_entity_id bigint,  created_at timestamptz not null default now(),  constraint email_attachments_document_type_check check (document_type in ('pdf','encargo','foto','documentacion','otro')),  constraint email_attachments_unique unique (email_message_id, provider_attachment_id, filename));create index if not exists email_messages_priority_idx  on public.email_messages(user_id, commercial_priority desc, received_at desc);create index if not exists email_messages_due_idx  on public.email_messages(user_id, response_due_at)  where needs_response = true and responded_at is null;create index if not exists email_alerts_user_status_idx  on public.email_alerts(user_id, status, due_at);create index if not exists email_attachments_message_idx  on public.email_attachments(email_message_id);alter table public.email_alerts enable row level security;alter table public.email_attachments enable row level security;drop policy if exists email_alerts_select_own on public.email_alerts;create policy email_alerts_select_own on public.email_alerts for selectusing (  auth.uid() is not null  and user_id = public.current_user_id()  and empresa_id = public.current_empresa_id());drop policy if exists email_alerts_insert_own on public.email_alerts;create policy email_alerts_insert_own on public.email_alerts for insertwith check (  auth.uid() is not null  and user_id = public.current_user_id()  and empresa_id = public.current_empresa_id());drop policy if exists email_alerts_update_own on public.email_alerts;create policy email_alerts_update_own on public.email_alerts for updateusing (  auth.uid() is not null  and user_id = public.current_user_id()  and empresa_id = public.current_empresa_id())with check (  user_id = public.current_user_id()  and empresa_id = public.current_empresa_id());drop policy if exists email_attachments_select_own on public.email_attachments;create policy email_attachments_select_own on public.email_attachments for selectusing (  auth.uid() is not null  and user_id = public.current_user_id()  and empresa_id = public.current_empresa_id());drop policy if exists email_attachments_insert_own on public.email_attachments;create policy email_attachments_insert_own on public.email_attachments for insertwith check (  auth.uid() is not null  and user_id = public.current_user_id()  and empresa_id = public.current_empresa_id());